var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"같은 시간","JPN":"同時刻","ENG":"Meanwhile","TWN":"同一時間","DEU":"Meanwhile","FRA":"Meanwhile"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color> 외곽 구역\\n<color=#ffd34c>프리드웬 기관</color> 비밀 격리 시설 LAKE-13","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>外郭地域\\n<color=#ffd34c>プリドウェン機関</color>秘密隔離施設LAKE-13","ENG":"[[","TWN":"管理局直轄都市<color=#ffd34c>查雷德</color>外郭區域\\n<color=#ffd34c>普利多溫機關</color>祕密隔離設施LAKE-13","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"……그럼, 간단한 이론 설명부터 해볼까?","JPN":"……それじゃ、大まかな理論から説明しようかしら。","ENG":"...Shall we start with a simple theoretical explanation?","TWN":"……那先從理論簡單說明一下吧？"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"신의 그릇이라는 건, 결국 원시 종교 형태인 샤머니즘으로부터 근거를 두고 있어.","JPN":"神の器っていうのは、原始的宗教の形をとったシャーマニズムに基づいているの。","ENG":"What people call a god's vessel ultimately traces its roots back to shamanism, one of the most primitive forms of religion.","TWN":"所謂的神之器皿，可以追溯到薩滿信仰這種原始宗教形態。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"수천 년 인간의 역사에서, 신과 인간을 중계하는 메신저는 늘 존재해왔으니까.","JPN":"数千年にわたる人類の歴史の中で、神と人間との間を仲保するメッセンジャーは常に存在してきたからね。","ENG":"Throughout thousands of years of human history, there have always been messengers who mediated between gods and humans.","TWN":"在人類數千年的歷史中，總是作為神與人之間的媒介存在著。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"영매, 무녀, 무당, 신관, 주술사, 마법사 아무튼 기타 등등…….","JPN":"霊媒、巫女、シャーマン、神官、呪術師、魔法使いなどなど……","ENG":"Mediums, shrine maidens, shamans, priests, sorcerers, mages, and so on...","TWN":"靈媒、巫女、巫師、神官、咒術師、魔法師，諸如此類……"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"과거에는 메신저들을 그렇게 부르며 숭배해왔지.","JPN":"過去、メッセンジャーはそう呼ばれ崇拝されてきたわ。","ENG":"In the past, people revered them under those names.","TWN":"在過去，大家便是這樣稱呼傳訊者並崇敬他們。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"여기에 조금 더 현대적인 해설을 덧붙이자면…….","JPN":"ここに、もう少し現代的な解説を加えるとすれば……","ENG":"To put a slightly more modern spin on it...","TWN":"如果再加上一點現代化說明……"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"뭐랄까? 신의 뜻을 빌려, 현실을 개변하는 인간이라고 해야할까?","JPN":"そうねえ。神の意思を借りて、現実を改変する人間とでも言うべきかしら？","ENG":"You could say they were humans who borrowed divine will to alter reality.","TWN":"該怎麼說呢？大概就是借用神的意志，改變現實人類這樣的存在吧？"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"과거부터 존재해왔던 그들은 아마도 <color=#ffd34c>카운터</color>였을 거야.","JPN":"過去より存在してきた彼らは、おそらく<color=#ffd34c>カウンター</color>だったと思うわ。","ENG":"Those who existed since ancient times were probably what we now call <color=#ffd34c>Counters</color>.","TWN":"從過去到現在仍存在的那些人，應該就是<color=#ffd34c>制裁者</color>吧。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"카운터라고?","JPN":"カウンター？","ENG":"Counters?","TWN":"制裁者？"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"그럼, 모든 카운터가 그릇이 될 수도 있다는 거야?","JPN":"だったら、すべてのカウンターは器になれるってことか？","ENG":"Then does that mean any Counter could become a vessel?","TWN":"那麼所有制裁者都有可能成為器皿嗎？"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"정확히 말하면, 그릇으로서의 소질을 가지고 있다는 뜻이지.","JPN":"正確に言うと、器としての素質を持っているということね。","ENG":"More precisely, it means they possess the potential to be a vessel.","TWN":"確切來說，是具備成為器皿的資質。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"아무래도 신이라는 존재는 제법 입맛이 까다로운 편인 것 같거든~","JPN":"どうやら神って存在は選り好みが激しいタイプみたいでね～","ENG":"Gods, you see, tend to be rather picky about their tastes.","TWN":"畢竟神這種存在，可是相當挑剔的喔～"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"우리 종교학부는 그동안 그릇과 신성에 관한 연구를 계속해왔어.","JPN":"私たち宗教学部は今まで、器と神聖に関する研究を続けてきたわ。","ENG":"The Religion Department has long been researching vessels and Divinity.","TWN":"我們宗教學院，長久以來都在持續研究器皿與神性的關係。"},"stage":{"bg":"QLIPHOTH","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그 결과, 어떠한 신적 존재가 현실에 실재하기 위해서는…….","JPN":"その結果、神に等しい存在が現実に実在するためには……","ENG":"As a result, we learned that for a divine being to truly exist in reality...","TWN":"研究結果顯示，為了讓某種神性存在於現實……"},"stage":{"bg":"QLIPHOTH","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"신성을 견딜 수 있는 특이체질의 카운터가 필요하다는 걸 알게 되었지.","JPN":"神聖に耐えられる特異体質のカウンターが必要だということが分かったの。","ENG":"It requires a Counter with a unique constitution capable of enduring Divinity.","TWN":"就必須要有具備能承受神性特殊體質的制裁者。"},"stage":{"bg":"QLIPHOTH","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"물론, 신을 담는 그릇의 질의 따라, 그 격이 결정되는 모양이지만.","JPN":"神を宿す器の質によってその格が決まるみたいだってこともね。","ENG":"Of course, its stature seems to be determined by the quality of the vessel that contains the god.","TWN":"當然，根據容納神的器皿品質，位階似乎也有所差異。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"하지만 이상하군요.","JPN":"でも、おかしいですね。","ENG":"But that's strange.","TWN":"那這就奇怪了。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그 사고가 있기 전까지, 리오나 하트는 평범한 여학생이었습니다.","JPN":"あの事故が起きる前まで、リオナ・ハートは普通の学生でした。","ENG":"Until that accident, Liona Hartt was just an ordinary schoolgirl.","TWN":"在那起事故發生前，萊歐娜．哈特不過是個普通的學生。"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"카운터가 아니었던 인간이, 각성과 함께 우연히 그릇이 되었다고요?","JPN":"カウンターでもなかった人間が、覚醒と同時に偶然にも器になった……ということですか？","ENG":"Are you saying someone who wasn't a Counter became a vessel by sheer coincidence upon awakening?","TWN":"不是制裁者的普通人，卻在覺醒的同時偶然成為器皿？"},"stage":{"bg":"PRYDWEN","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"역시 기관장님이야, 제법 날카로운데?","JPN":"さすが機関長。鋭いわね。","ENG":"As expected of the Chief, you're quite sharp.","TWN":"不愧是機關長，相當敏銳呢。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"맞아, 이 아이는 그릇으로는 반푼이거든.","JPN":"そう。この子は器としては半人前なの。","ENG":"That's right. As a vessel, this girl is utterly inadequate.","TWN":"沒錯，這孩子只能算是半個器皿。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"원래라면 넘쳐흘러서, <color=#ffd34c>정보 말소</color>를 당해, 모두에게 잊힐 운명이었을 거야.","JPN":"本来なら溢れ出して、<color=#ffd34c>情報抹消</color>にあい、皆に忘れられる運命だったはずよ。","ENG":"Normally, she would have overflowed, undergone <color=#ffd34c>information erasure</color>, and been forgotten by everyone.","TWN":"照理說她早就該因為溢出遭到<color=#ffd34c>資訊抹消</color>，被所有人遺忘才對。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"정보 말소라고……?","JPN":"情報抹消だって……？","ENG":"Information erasure...?","TWN":"資訊抹消……？"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROI_PRYDWEN_GALAHAD_NULL","text":{"KOREA":"……쳇.","JPN":"……ちっ。","ENG":"...Tch.","TWN":"……嘖。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_GALAHAD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"이 아이가 잔해가 되지 않은 이유는 간단해.","JPN":"この子が残骸にならなかった理由は簡単よ。","ENG":"The reason she didn't become debris is simple.","TWN":"她之所以沒有淪為殘骸，理由其實很簡單。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그릇에서 넘치는 부분을, 이 아이의 검이 대신 감당해주고 있었으니까.","JPN":"器に収まりきれなかった分を、この子の剣が代わりに受け止めてくれていたから。","ENG":"Her sword was bearing the excess that spilled out of the vessel in her stead.","TWN":"因為由她的劍代為承受從器皿中溢出的部分了。"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"우리는 오래전부터 물질에 신성을 고정시키는 실험을 해왔어.","JPN":"私たちは結構前から物質に神聖を固定させる実験をしてきたわ。","ENG":"We've long been experimenting with fixing divinity into physical matter.","TWN":"我們從很久以前，就開始進行將神性固定於物質的實驗。"},"stage":{"bg":"MAINSTREAM_412010","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"수없이 많은 실패가 있었지만, 비교적 최근에 그 힌트를 발견했거든.","JPN":"幾度も失敗したけど、比較的最近そのヒントが見つかったの。","ENG":"There were countless failures, but we found a clue relatively recently.","TWN":"雖然失敗過無數次，但在不久前發現了一點線索。"},"stage":{"bg":"MAINSTREAM_7100013","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"검을 잃고, 홀로 신성을 감당하게 된 반푼이 <color=#ffd34c>그릇</color>과…….","JPN":"剣を失って一人で神聖に耐えるしかなくなった半人前の<color=#ffd34c>器</color>と……","ENG":"An inadequate <color=#ffd34c>vessel</color> forced to endure Divinity alone after losing her sword...","TWN":"失去劍、只能獨自承受神性的半個<color=#ffd34c>器皿</color>……"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"원래 검을 대체할 정도로 충분히 정보가 쌓인 <color=#ffd34c>요도</color>…….","JPN":"元の剣の代わりになれるほど十分な情報が蓄積された<color=#ffd34c>妖刀</color>……","ENG":"A <color=#ffd34c>demonic blade</color> that has accumulated enough information to replace that sword...","TWN":"以及原本就累積足以替代劍的資訊量的<color=#ffd34c>妖刀</color>……"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGNES_ESPR_NULL_NULL","text":{"KOREA":"그리고 <color=#ffd34c>의식</color> 수행에 적합한 환경까지…….","JPN":"そして<color=#ffd34c>儀式</color>の遂行に適合した環境まで……","ENG":"And an environment suitable for conducting a <color=#ffd34c>ritual</color>...","TWN":"再加上適合執行<color=#ffd34c>儀式</color>的環境……"},"stage":{"bg":"PRYDWEN","slots":{"L":null,"C":{"char_id":"AGNES_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"subtitle","speaker":null,"text":{"KOREA":"L30_1","JPN":"L30_1","ENG":"L30_1","TWN":"L30_1","DEU":"L30_1","FRA":"L30_1"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"subtitle","speaker":null,"text":{"KOREA":"L31_1","JPN":"L31_1","ENG":"L31_1","TWN":"L31_1","DEU":"L31_1","FRA":"L31_1"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};